import React, { useState, useEffect, useCallback } from "react";
import "./Internship.css";

export default function Internship() {
  const user = JSON.parse(localStorage.getItem("currentUser"));
  const [internships, setInternships] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedInternship, setSelectedInternship] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Fetch internships
  const fetchInternships = useCallback(async () => {
    try {
      const res = await fetch("http://localhost:5000/api/internships");
      const data = await res.json();
      setInternships(data);
      setFiltered(data);
    } catch (err) {
      console.error("Error fetching internships", err);
    }
  }, []);

  useEffect(() => {
    fetchInternships();
  }, [fetchInternships]);

  // Search/filter
  useEffect(() => {
    const filteredData = internships.filter((item) =>
      item.title.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setFiltered(filteredData);
  }, [searchTerm, internships]);

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this internship?")) return;
    try {
      await fetch(`http://localhost:5000/api/internships/${id}`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${user.token}` },
      });
      fetchInternships();
    } catch (err) {
      console.error("Delete failed", err);
    }
  };

  const handleEdit = (internship) => {
    setSelectedInternship(internship);
    setIsModalOpen(true);
  };

  const handleOpenModal = () => {
    setSelectedInternship(null);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setSelectedInternship(null);
    setIsModalOpen(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const form = e.target;
    const internshipData = {
      title: form.title.value,
      description: form.description.value,
      company: form.company.value,
      location: form.location.value,
    };

    const method = selectedInternship ? "PUT" : "POST";
    const endpoint = selectedInternship
      ? `http://localhost:5000/api/internships/${selectedInternship._id}`
      : "http://localhost:5000/api/internships";

    try {
      await fetch(endpoint, {
        method,
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${user.token}`,
        },
        body: JSON.stringify(internshipData),
      });
      fetchInternships();
      handleCloseModal();
    } catch (err) {
      console.error("Submit failed", err);
    }
  };

  const handleApply = async (internshipId) => {
    try {
      await fetch(`http://localhost:5000/api/applications`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${user.token}`,
        },
        body: JSON.stringify({ internshipId }),
      });
      alert("Applied successfully!");
    } catch (err) {
      console.error("Application failed", err);
    }
  };

  return (
    <div className="internship-page">
      <h2>Internship Opportunities</h2>

      {/* Search */}
      <input
        type="text"
        placeholder="Search internships..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        className="search-input"
      />

      {/* Add Button (Admin/HR only) */}
      {(user?.role === "admin" || user?.role === "hr") && (
        <button onClick={handleOpenModal} className="add-internship-btn">
          + Add Internship
        </button>
      )}

      {/* Internship List */}
      <div className="internship-list">
        {filtered.map((item) => (
          <div key={item._id} className="internship-card">
            <h3>{item.title}</h3>
            <p><strong>Company:</strong> {item.company}</p>
            <p><strong>Location:</strong> {item.location}</p>
            <p>{item.description}</p>

            {/* Actions */}
            {user?.role === "student" ? (
              <button onClick={() => handleApply(item._id)}>Apply</button>
            ) : (
              <div className="action-buttons">
                <button onClick={() => handleEdit(item)}>Edit</button>
                <button onClick={() => handleDelete(item._id)}>Delete</button>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="modal-backdrop">
          <form onSubmit={handleSubmit} className="modal">
            <h3>{selectedInternship ? "Edit Internship" : "Add Internship"}</h3>
            <input name="title" defaultValue={selectedInternship?.title} required placeholder="Title" />
            <input name="company" defaultValue={selectedInternship?.company} required placeholder="Company" />
            <input name="location" defaultValue={selectedInternship?.location} required placeholder="Location" />
            <textarea name="description" defaultValue={selectedInternship?.description} required placeholder="Description" />
            <div className="modal-actions">
              <button type="submit">Save</button>
              <button type="button" onClick={handleCloseModal}>Cancel</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
}
